  let cart = [];
  let cartOpen = false;
  const capybaraImg = 'data:image/png;base64,';

  const products = {
    1: { name: 'Lunch Box 1', basePrice: 125, icon: '🐣', extras: { 'Salchipulpos + catsup 🐙': 25 } },
    2: { name: 'Lunch Box 2', basePrice: 130, icon: '🥐', extras: { 'Upgrade croissant completo 🥐': 0 } }
  };

  function changeQty(id, delta) {
    const el = document.getElementById(id);
    let val = parseInt(el.textContent) + delta;
    if (val < 1) val = 1;
    el.textContent = val;
  }

  function selectArt(box, el) {
    document.querySelectorAll(`#art${box} .art-opt`).forEach(o => o.classList.remove('active'));
    el.classList.add('active');
  }

  function toggleExtra(el) {
    el.classList.toggle('selected');
  }

  function addToCart(boxId) {
    // Block if other box type already in cart
    const otherBoxInCart = cart.find(i => i.boxId !== boxId);
    if (otherBoxInCart) {
      showToast(`⚠️ Ya tienes un ${otherBoxInCart.name} en tu pedido`);
      return;
    }

    const p = products[boxId];
    const qty = parseInt(document.getElementById(`qty${boxId}`).textContent);

    // Get selected art
    const activeArt = document.querySelector(`#art${boxId} .art-opt.active`);
    const artName = activeArt ? activeArt.dataset.art : 'Osito';

    // Block if different art type already in cart
    const otherArtInCart = cart.find(i => i.art !== artName);
    if (otherArtInCart) {
      showToast(`⚠️ Ya tienes ${otherArtInCart.art} en tu pedido. Un pedido = una sola figura.`);
      return;
    }

    // Get extras
    const card = document.getElementById(`card${boxId}`);
    const checkedExtras = [];
    let extrasTotal = 0;

    card.querySelectorAll('.extra-option.selected').forEach(opt => {
      const label = opt.querySelector('.extra-label').textContent;
      const price = parseInt(opt.dataset.price) || 0;
      checkedExtras.push({ label, price });
      extrasTotal += price;
    });

    const unitPrice = p.basePrice + extrasTotal;
    const totalPrice = unitPrice * qty;

    const item = {
      id: Date.now(),
      boxId,
      name: p.name,
      icon: p.icon,
      art: artName,
      qty,
      unitPrice,
      totalPrice,
      extras: checkedExtras
    };

    cart.push(item);
    renderCart();
    updateCardLock();
    showToast(`✅ ${qty}x ${p.name} agregado!`);
    if (!cartOpen) toggleCart();
  }

  function removeFromCart(id) {
    cart = cart.filter(i => i.id !== id);
    renderCart();
    updateCardLock();
  }

  function updateCardLock() {
    const activeBoxId = cart.length > 0 ? cart[0].boxId : null;

    [1, 2].forEach(id => {
      const card = document.getElementById(`card${id}`);
      const btn  = card.querySelector('.add-btn');
      const overlay = card.querySelector('.lock-overlay');

      if (activeBoxId && activeBoxId !== id) {
        // Lock this card
        card.style.opacity = '0.45';
        card.style.pointerEvents = 'none';
        if (!overlay) {
          const div = document.createElement('div');
          div.className = 'lock-overlay';
          div.innerHTML = `<div class="lock-msg">🔒 Para pedir este box,<br>envía primero tu pedido actual<br>y haz uno nuevo.</div>`;
          card.appendChild(div);
        }
      } else {
        // Unlock
        card.style.opacity = '1';
        card.style.pointerEvents = 'auto';
        const existingOverlay = card.querySelector('.lock-overlay');
        if (existingOverlay) existingOverlay.remove();
      }
    });
  }

  function renderCart() {
    const container = document.getElementById('cartItems');
    const badge = document.getElementById('cartBadge');
    const totalEl = document.getElementById('cartTotal');
    const btn = document.getElementById('whatsappBtn');

    const totalItems = cart.reduce((s, i) => s + i.qty, 0);
    badge.textContent = totalItems;

    if (cart.length === 0) {
      container.innerHTML = `<div class="cart-empty"><span class="empty-icon">🥞</span><p>Tu carrito está vacío</p></div>`;
      totalEl.textContent = '$0';
      btn.disabled = true;
      return;
    }

    const total = cart.reduce((s, i) => s + i.totalPrice, 0);
    totalEl.textContent = `$${total}`;
    btn.disabled = false;

    container.innerHTML = cart.map(item => {
      const extrasText = item.extras.length ? item.extras.map(e => e.label).join(', ') : 'Sin extras';
      const colorDot = item.boxId === 1
        ? 'background:#FFD93D; border:2px solid #E6B800;'
        : 'background:#FFB3C6; border:2px solid #E8809A;';
      return `
        <div class="cart-item">
          <div class="item-tag" style="${colorDot}"></div>
          <div class="item-details">
            <div class="item-name">${item.qty}x ${item.name}</div>
            <div class="item-meta">
              ${
                item.art === 'Capibara' ? `<img src="${capybaraImg}" style="width:18px;height:18px;object-fit:contain;vertical-align:middle;border-radius:50%;margin-right:4px;">` :
                item.art === 'Osito' ? `<span style="font-size:16px;vertical-align:middle;margin-right:4px;">🐻</span>` :
                item.art === 'Pollito' ? `<span style="font-size:16px;vertical-align:middle;margin-right:4px;">🐥</span>` : ''
              }${item.art} · ${extrasText}
            </div>
            <div class="item-bottom">
              <div class="item-price">$${item.totalPrice}</div>
              <button class="remove-btn" onclick="removeFromCart(${item.id})">🗑️</button>
            </div>
          </div>
        </div>
      `;
    }).join('');
  }

  function toggleCart() {
    cartOpen = !cartOpen;
    document.getElementById('cartPanel').classList.toggle('open', cartOpen);
    document.getElementById('cartOverlay').classList.toggle('open', cartOpen);
  }

  function showToast(msg) {
    const t = document.getElementById('toast');
    t.textContent = msg;
    t.classList.add('show');
    setTimeout(() => t.classList.remove('show'), 2600);
  }

  function sendWhatsApp() {
    const name = document.getElementById('clientName').value.trim();
    const date = document.getElementById('deliveryDate').value;
    const time = document.getElementById('deliveryTime').value;
    const notes = document.getElementById('notes').value.trim();

    if (cart.length === 0) { showToast('⚠️ Tu carrito está vacío'); return; }
    if (!name) { showToast('⚠️ Ingresa tu nombre por favor'); return; }
    if (!date) { showToast('⚠️ Selecciona una fecha de entrega'); return; }

    const total = cart.reduce((s, i) => s + i.totalPrice, 0);

    let msg = `🥞 *PEDIDO NAPPANCAKES*\n`;
    msg += `━━━━━━━━━━━━━━━━\n`;
    msg += `👤 *Cliente:* ${name}\n`;
    msg += `📅 *Fecha:* ${formatDate(date)}\n`;
    if (time) msg += `⏰ *Hora:* ${time}\n`;
    if (notes) msg += `📍 *Notas:* ${notes}\n`;
    msg += `━━━━━━━━━━━━━━━━\n`;
    msg += `*PRODUCTOS:*\n`;

    cart.forEach(item => {
      msg += `\n🎁 ${item.qty}x ${item.name} — $${item.totalPrice}\n`;
      msg += `   🎨 PancakeART: ${item.art}\n`;
      if (item.extras.length) {
        msg += `   ➕ Extras: ${item.extras.map(e => e.label).join(', ')}\n`;
      }
    });

    msg += `\n━━━━━━━━━━━━━━━━\n`;
    msg += `💰 *TOTAL: $${total} MXN*\n`;
    msg += `\n¡Gracias por tu pedido! 🐻✨`;

    // Replace with actual WhatsApp number
    const phone = '528123509768';
    const url = `https://wa.me/${phone}?text=${encodeURIComponent(msg)}`;
    window.open(url, '_blank');
  }

  function formatDate(dateStr) {
    const [y, m, d] = dateStr.split('-');
    const months = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
    return `${d} ${months[parseInt(m)-1]} ${y}`;
  }

  function updateSummary() {
    const name  = document.getElementById('clientName').value.trim();
    const date  = document.getElementById('deliveryDate').value;
    const time  = document.getElementById('deliveryTime').value;
    const notes = document.getElementById('notes').value.trim();
    const box   = document.getElementById('orderSummary');

    if (!name && !date) {
      box.innerHTML = `<div class="summary-empty">📋 Llena los datos del pedido abajo para ver el resumen aquí.</div>`;
      return;
    }

    let html = '';
    if (name)  html += `<div class="summary-row"><span>👤</span><span><b>${name}</b></span></div>`;
    if (date)  html += `<div class="summary-row"><span>📅</span><span>${formatDate(date)}${time ? ' &nbsp;⏰ ' + time : ''}</span></div>`;
    if (notes) html += `<div class="summary-row"><span>📍</span><span>${notes}</span></div>`;

    box.innerHTML = html;
  }

  // Set min date to today
  const today = new Date().toISOString().split('T')[0];
  document.getElementById('deliveryDate').min = today;

  // Wire up live summary updates
  ['clientName','deliveryDate','deliveryTime','notes'].forEach(id => {
    document.getElementById(id).addEventListener('input', updateSummary);
  });

  renderCart();

