function goTo(page) {
  if (page === 'nappan-lunchbox.html') {
    showPage('lunchbox');
  } else if (page === 'nappan-box.html') {
    showPage('nappanbox');
    initNappanBox();
  } else {
    showComingSoon();
  }
}

